part 'items_provider.g.dart';

@riverpod
class Items extends _$Items {
  @override
  Future<List<Item>> build() async {
    // Simulate loading items from storage/API
    await Future.delayed(const Duration(milliseconds: 500));
    return [];
  }

  Future<void> addItem(Item item) async {
    state = const AsyncValue.loading();
    state = await AsyncValue.guard(() async {
      final currentItems = await future;
      return [...currentItems, item];
    });
  }

  Future<void> removeItem(int id) async {
    state = const AsyncValue.loading();
    state = await AsyncValue.guard(() async {
      final currentItems = await future;
      return currentItems.where((item) => item.id != id).toList();
    });
  }

  Future<void> updateItem(Item updatedItem) async {
    state = const AsyncValue.loading();
    state = await AsyncValue.guard(() async {
      final currentItems = await future;
      return [
        for (final item in currentItems)
          if (item.id == updatedItem.id) updatedItem else item,
      ];
    });
  }

  Future<void> refresh() async {
    state = const AsyncValue.loading();
    state = await AsyncValue.guard(() async {
      // Simulate refreshing from storage/API
      await Future.delayed(const Duration(milliseconds: 300));
      return state.value ?? [];
    });
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';

import 'package:riverpod_annotation/riverpod_annotation.dart';
import 'package:shared_preferences/shared_preferences.dart';

part 'settings_provider.g.dart';

@riverpod
class Settings extends _$Settings {
  @override
  Future<Map<String, dynamic>> build() async {
    return await _loadSettings();
  }

  Future<Map<String, dynamic>> _loadSettings() async {
    final prefs = await SharedPreferences.getInstance();
    return {
      'theme': prefs.getString('theme') ?? 'light',
      'notifications': prefs.getBool('notifications') ?? true,
    };
  }

  Future<void> updateTheme(String theme) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('theme', theme);

    final currentSettings = state.value ?? {};
    state = AsyncValue.data({
      ...currentSettings,
      'theme': theme,
    });
  }

  Future<void> updateNotifications(bool enabled) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool('notifications', enabled);

    final currentSettings = state.value ?? {};
    state = AsyncValue.data({
      ...currentSettings,
      'notifications': enabled,
    });
  }

  Future<void> resetSettings() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove('theme');
    await prefs.remove('notifications');

    state = const AsyncValue.data({
      'theme': 'light',
      'notifications': true,
    });
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';

import 'package:go_router/go_router.dart';

import 'package:a_scientific_calculator_application_to_perform_mor/features/calculator/models/calculation_history.dart';
import 'package:a_scientific_calculator_application_to_perform_mor/features/calculator/providers/calculator_provider.dart';
import 'package:a_scientific_calculator_application_to_perform_mor/features/home/presentation/widgets/calculator_display.dart';
import 'package:a_scientific_calculator_application_to_perform_mor/features/home/presentation/widgets/calculator_keypad.dart';

class HomeScreen extends ConsumerWidget {
  const HomeScreen({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final calculatorState = ref.watch(calculatorProvider);
    final historyAsync = ref.watch(calculationHistoryProvider);

    return Scaffold(
      backgroundColor: Theme.of(context).colorScheme.surface,
      appBar: AppBar(
        title: const Text('Scientific Calculator'),
        backgroundColor: Theme.of(context).colorScheme.primaryContainer,
        elevation: 0,
        actions: [
          IconButton(
            onPressed: () {
              ref.read(calculatorProvider.notifier).clearHistory();
            },
            icon: const Icon(Icons.history),
            tooltip: 'View History',
            semanticLabel: 'View calculation history',
          ),
          IconButton(
            onPressed: () {
              ref.read(calculatorProvider.notifier).clearAll();
            },
            icon: const Icon(Icons.clear_all),
            tooltip: 'Clear All',
            semanticLabel: 'Clear all calculations',
          ),
        ],
      ),
      body: SafeArea(
        child: Column(
          children: [
            // Calculator Display Section
            Expanded(
              flex: 2,
              child: Container(
                width: double.infinity,
                padding: const EdgeInsets.all(16.0),
                decoration: BoxDecoration(
                  color: Theme.of(context).colorScheme.surfaceVariant,
                  borderRadius: const BorderRadius.only(
                    bottomLeft: Radius.circular(24),
                    bottomRight: Radius.circular(24),
                  ),
                ),
                child: CalculatorDisplay(
                  currentInput: calculatorState.currentInput,
                  result: calculatorState.result,
                  expression: calculatorState.expression,
                  isError: calculatorState.hasError,
                ),
              ),
            ),
            const SizedBox(height: 16),
            // Keypad Section
            Expanded(
              flex: 4,
              child: Padding(
                padding: const EdgeInsets.symmetric(horizontal: 16.0),
                child: CalculatorKeypad(
                  onNumberPressed: (number) {
                    ref.read(calculatorProvider.notifier).inputNumber(number);
                  },
                  onOperatorPressed: (operator) {
                    ref.read(calculatorProvider.notifier).inputOperator(operator);
                  },
                  onFunctionPressed: (function) {
                    ref.read(calculatorProvider.notifier).inputFunction(function);
                  },
                  onEqualsPressed: () {
                    ref.read(calculatorProvider.notifier).calculate();
                  },
                  onClearPressed: () {
                    ref.read(calculatorProvider.notifier).clear();
                  },
                  onBackspacePressed: () {
                    ref.read(calculatorProvider.notifier).backspace();
                  },
                ),
              ),
            ),
            // History Preview Section
            if (historyAsync.hasValue && historyAsync.value!.isNotEmpty)
              Container(
                height: 80,
                margin: const EdgeInsets.all(16),
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: Theme.of(context).colorScheme.surfaceVariant,
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(
                    color: Theme.of(context).colorScheme.outline.withOpacity(0.2),
                  ),
                ),
                child: historyAsync.when(
                  loading: () => const Center(
                    child: SizedBox(
                      height: 20,
                      width: 20,
                      child: CircularProgressIndicator(strokeWidth: 2),
                    ),
                  ),
                  error: (error, stack) => Center(
                    child: Row(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                        Icon(
                          Icons.error_outline,
                          size: 16,
                          color: Theme.of(context).colorScheme.error,
                        ),
                        const SizedBox(width: 4),
                        Text(
                          'History error',
                          style: TextStyle(
                            color: Theme.of(context).colorScheme.error,
                            fontSize: 12,
                          ),
                        ),
                        const SizedBox(width: 8),
                        TextButton(
                          onPressed: () => ref.invalidate(calculationHistoryProvider),
                          style: TextButton.styleFrom(
                            padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                            minimumSize: Size.zero,
                            tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                          ),
                          child: const Text('Retry', style: TextStyle(fontSize: 12)),
                        ),
                      ],
                    ),
                  ),
                  data: (history) => _buildHistoryPreview(context, history),
                ),
              ),
          ],
        ),
      ),
      floatingActionButton: FloatingActionButton.extended(
        onPressed: () {
          _showHistoryBottomSheet(context, ref);
        },
        icon: const Icon(Icons.history),
        label: const Text('History'),
        tooltip: 'View full calculation history',
      ),
    );
  }

  Widget _buildHistoryPreview(BuildContext context, List<CalculationHistory> history) {
    final recent = history.take(3).toList();

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          'Recent Calculations',
          style: Theme.of(context).textTheme.labelSmall?.copyWith(
            color: Theme.of(context).colorScheme.onSurfaceVariant,
          ),
        ),
        const SizedBox(height: 4),
        Expanded(
          child: ListView.separated(
            scrollDirection: Axis.horizontal,
            itemCount: recent.length,
            separatorBuilder: (context, index) => const SizedBox(width: 16),
            itemBuilder: (context, index) {
              final calculation = recent[index];
              return Container(
                padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
                decoration: BoxDecoration(
                  color: Theme.of(context).colorScheme.surface,
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      calculation.expression,
                      style: Theme.of(context).textTheme.bodySmall,
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                    ),
                    Text(
                      '= ${calculation.result}',
                      style: Theme.of(context).textTheme.bodySmall?.copyWith(
                        fontWeight: FontWeight.bold,
                        color: Theme.of(context).colorScheme.primary,
                      ),
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                    ),
                  ],
                ),
              );
            },
          ),
        ),
      ],
    );
  }

  void _showHistoryBottomSheet(BuildContext context, WidgetRef ref) {
    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),
      ),
      builder: (context) => DraggableScrollableSheet(
        initialChildSize: 0.7,
        maxChildSize: 0.9,
        minChildSize: 0.3,
        expand: false,
        builder: (context, scrollController) {
          return Consumer(
            builder: (context, ref, child) {
              final historyAsync = ref.watch(calculationHistoryProvider);

              return Container(
                decoration: BoxDecoration(
                  color: Theme.of(context).colorScheme.surface,
                  borderRadius: const BorderRadius.vertical(top: Radius.circular(20)),
                ),
                child: Column(
                  children: [
                    Container(
                      width: 40,
                      height: 4,
                      margin: const EdgeInsets.symmetric(vertical: 12),
                      decoration: BoxDecoration(
                        color: Theme.of(context).colorScheme.onSurfaceVariant.withOpacity(0.4),
                        borderRadius: BorderRadius.circular(2),
                      ),
                    ),
                    Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 16),
                      child: Row(
                        children: [
                          Text(
                            'Calculation History',
                            style: Theme.of(context).textTheme.titleLarge,
                          ),
                          const Spacer(),
                          TextButton.icon(
                            onPressed: () {
                              ref.read(calculatorProvider.notifier).clearHistory();
                            },
                            icon: const Icon(Icons.delete_outline, size: 16),
                            label: const Text('Clear'),
                            style: TextButton.styleFrom(
                              foregroundColor: Theme.of(context).colorScheme.error,
                            ),
                          ),
                        ],
                      ),
                    ),
                    const Divider(),
                    Expanded(
                      child: historyAsync.when(
                        loading: () => const Center(child: CircularProgressIndicator()),
                        error: (error, stack) => Center(
                          child: Column(
                            mainAxisAlignment: MainAxisAlignment.center,
                            children: [
                              Icon(
                                Icons.error_outline,
                                size: 48,
                                color: Theme.of(context).colorScheme.error,
                              ),
                              const SizedBox(height: 16),
                              Text(
                                'Failed to load history',
                                style: Theme.of(context).textTheme.titleMedium,
                              ),
                              const SizedBox(height: 8),
                              FilledButton.tonal(
                                onPressed: () => ref.invalidate(calculationHistoryProvider),
                                child: const Text('Retry'),
                              ),
                            ],
                          ),
                        ),
                        data: (history) => history.isEmpty
                            ? Center(
                                child: Column(
                                  mainAxisAlignment: MainAxisAlignment.center,
                                  children: [
                                    Icon(
                                      Icons.history,
                                      size: 48,
                                      color: Theme.of(context).colorScheme.onSurfaceVariant,
                                    ),
                                    const SizedBox(height: 16),
                                    Text(
                                      'No calculations yet',
                                      style: Theme.of(context).textTheme.titleMedium,
                                    ),
                                    const SizedBox(height: 8),
                                    Text(
                                      'Your calculation history will appear here',
                                      style: Theme.of(context).textTheme.bodyMedium?.copyWith(
                                        color: Theme.of(context).colorScheme.onSurfaceVariant,
                                      ),
                                      textAlign: TextAlign.center,
                                    ),
                                  ],
                                ),
                              )
                            : ListView.separated(
                                controller: scrollController,
                                padding: const EdgeInsets.all(16),
                                itemCount: history.length,
                                separatorBuilder: (context, index) => const SizedBox(height: 8),
                                itemBuilder: (context, index) {
                                  final calculation = history[index];
                                  return Card(
                                    child: ListTile(
                                      title: Text(
                                        calculation.expression,
                                        style: Theme.of(context).textTheme.bodyLarge,
                                      ),
                                      subtitle: Text(
                                        '= ${calculation.result}',
                                        style: Theme.of(context).textTheme.titleMedium?.copyWith(
                                          color: Theme.of(context).colorScheme.primary,
                                          fontWeight: FontWeight.bold,
                                        ),
                                      ),
                                      trailing: Text(
                                        _formatDateTime(calculation.timestamp),
                                        style: Theme.of(context).textTheme.bodySmall?.copyWith(
                                          color: Theme.of(context).colorScheme.onSurfaceVariant,
                                        ),
                                      ),
                                      onTap: () {
                                        ref.read(calculatorProvider.notifier).loadFromHistory(calculation);
                                        Navigator.of(context).pop();
                                      },
                                    ),
                                  );
                                },
                              ),
                      ),
                    ),
                  ],
                ),
              );
            },
          );
        },
      ),
    );
  }

  String _formatDateTime(DateTime dateTime) {
    final now = DateTime.now();
    final difference = now.difference(dateTime);

    if (difference.inDays > 0) {
      return '${difference.inDays}d ago';
    } else if (difference.inHours > 0) {
      return '${difference.inHours}h ago';
    } else if (difference.inMinutes > 0) {
      return '${difference.inMinutes}m ago';
    } else {
      return 'Just now';
    }
  }
}

import 'package:flutter/material.dart';

class CalculatorDisplay extends StatelessWidget {
  final String currentInput;
  final String result;
  final String expression;
  final bool isError;

  const CalculatorDisplay({
    super.key,
    required this.currentInput,
    required this.result,
    required this.expression,
    required this.isError,
  });

  @override
  Widget build(BuildContext context) {
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(16.0),
      child: Column(
        mainAxisAlignment: MainAxisAlignment.end,
        crossAxisAlignment: CrossAxisAlignment.end,
        children: [
          // Expression display
          if (expression.isNotEmpty)
            Container(
              width: double.infinity,
              padding: const EdgeInsets.symmetric(vertical: 8.0),
              child: SingleChildScrollView(
                scrollDirection: Axis.horizontal,
                reverse: true,
                child: Semantics(
                  label: 'Current expression: $expression',
                  child: Text(
                    expression,
                    style: Theme.of(context).textTheme.bodyLarge?.copyWith(
                      color: Theme.of(context).colorScheme.onSurfaceVariant,
                      fontFamily: 'monospace',
                    ),
                    textAlign: TextAlign.end,
                  ),
                ),
              ),
            ),

          const SizedBox(height: 8),

          // Main display
          Container(
            width: double.infinity,
            padding: const EdgeInsets.symmetric(vertical: 8.0),
            child: SingleChildScrollView(
              scrollDirection: Axis.horizontal,
              reverse: true,
              child: Semantics(
                label: isError 
                    ? 'Error: $currentInput'
                    : result.isNotEmpty 
                        ? 'Result: $result'
                        : 'Input: ${currentInput.isEmpty ? "0" : currentInput}',
                child: Text(
                  _getDisplayText(),
                  style: Theme.of(context).textTheme.displayMedium?.copyWith(
                    color: isError 
                        ? Theme.of(context).colorScheme.error
                        : result.isNotEmpty
                            ? Theme.of(context).colorScheme.primary
                            : Theme.of(context).colorScheme.onSurface,
                    fontWeight: FontWeight.w300,
                    fontFamily: 'monospace',
                  ),
                  textAlign: TextAlign.end,
                  maxLines: 2,
                  overflow: TextOverflow.ellipsis,
                ),
              ),
            ),
          ),

          // Small indicators
          if (!isError && result.isNotEmpty && currentInput != result)
            Container(
              margin: const EdgeInsets.only(top: 8),
              padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
              decoration: BoxDecoration(
                color: Theme.of(context).colorScheme.primaryContainer,
                borderRadius: BorderRadius.circular(12),
              ),
              child: Text(
                'Tap = to confirm',
                style: Theme.of(context).textTheme.labelSmall?.copyWith(
                  color: Theme.of(context).colorScheme.onPrimaryContainer,
                ),
              ),
            ),
        ],
      ),
    );
  }

  String _getDisplayText() {
    if (isError) {
      return currentInput.isEmpty ? 'Error' : currentInput;
    }

    if (result.isNotEmpty) {
      return result;
    }

    return currentInput.isEmpty ? '0' : currentInput;
  }
}

import 'package:flutter/material.dart';
